import{_ as a,c as s,o as m,f as e}from"./plugin-vue_export-helper.ecc8ebe5.js";const y='{"title":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430","description":"","frontmatter":{"title":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430","subtitle":"\u041A\u043B\u044E\u0447\u0435\u0432\u043E\u0435 \u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u0412\u0430\u0441\u0443\u0433\u0443\u043F\u0442\u044B","sans":"\u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u093E","trans":"\u015Bivas\u016Btr\u0101","tags":"text","date":"2021-07-01T00:00:00.000Z"},"headers":[{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C \u043F\u0435\u0440\u0432\u0430\u044F","slug":"\u0447\u0430\u0441\u0442\u044C-\u043F\u0435\u0440\u0432\u0430\u044F"},{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C \u0432\u0442\u043E\u0440\u0430\u044F","slug":"\u0447\u0430\u0441\u0442\u044C-\u0432\u0442\u043E\u0440\u0430\u044F"},{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C \u0442\u0440\u0435\u0442\u044C\u044F","slug":"\u0447\u0430\u0441\u0442\u044C-\u0442\u0440\u0435\u0442\u044C\u044F"}],"relativePath":"texts/shiva-sutra/index.md","lastUpdated":1625159513332}',p={},t=e('<h2 id="\u0447\u0430\u0441\u0442\u044C-\u043F\u0435\u0440\u0432\u0430\u044F" tabindex="-1">\u0427\u0430\u0441\u0442\u044C \u043F\u0435\u0440\u0432\u0430\u044F <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-\u043F\u0435\u0440\u0432\u0430\u044F" aria-hidden="true">#</a></h2><p class="sans">\u0936\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F</p><p class="trans">\u015A\u0101mbhavop\u0101ya</p><p>\u041C\u0435\u0442\u043E\u0434, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043D\u0430 \u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F \u0428\u0430\u043C\u0431\u0445\u0443 (\u0428\u0438\u0432\u044B)</p><div class="stanza"><a href="#s1.1" id="s1.1" class="num">1.1</a><p class="sans">\u091A\u0948\u0924\u0928\u094D\u092F\u092E\u093E\u0924\u094D\u092E\u093E \u0965\u0967\u0965</p><p class="trans">Caitanyam\u0101tm\u0101 \u09651\u0965</p><p>\u0412\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0435 \u0438 \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> [\u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(\u0101tm\u0101)</em></p></div><div class="stanza"><a href="#s1.2" id="s1.2" class="num">1.2</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0928\u094D\u0927\u0903 \u0965\u0968\u0965</p><p class="trans">J\xF1\u0101na\u1E41 bandha\u1E25 \u09652\u0965</p><p>[\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u2014 \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25)</em></p></div><div class="stanza"><a href="#s1.3" id="s1.3" class="num">1.3</a><p class="sans">\u092F\u094B\u0928\u093F\u0935\u0930\u094D\u0917\u0903 \u0915\u0932\u093E\u0936\u0930\u0940\u0930\u092E\u094D \u0965\u0969\u0965</p><p class="trans">Yonivarga\u1E25 kal\u0101\u015Bar\u012Bram \u09653\u0965</p><p>\u0427\u0440\u0435\u0432\u043E <em>(yoni)</em> <em>(\u0438 \u0435\u0433\u043E)</em> \u043E\u0442\u043F\u0440\u044B\u0441\u043A\u0438 <em>(varga\u1E25)</em>, [\u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0442\u0435\u043C, \u0447\u044C\u044F] \u0444\u043E\u0440\u043C\u0430 <em>(\u015Bar\u012Bram)</em> \u2014 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(kal\u0101)</em>, [\u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u0440\u0430\u0431\u043E\u0449\u0430\u044E\u0442].</p></div><div class="stanza"><a href="#s1.4" id="s1.4" class="num">1.4</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u0902 \u092E\u093E\u0924\u0943\u0915\u093E \u0965\u096A\u0965</p><p class="trans">J\xF1\u0101n\u0101dhi\u1E63\u1E6Dh\u0101na\u1E41 m\u0101t\u1E5Bk\u0101 \u09654\u0965</p><p>\u041E\u0441\u043D\u043E\u0432\u0430 <em>(adhi\u1E63\u1E6Dh\u0101nam)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> \u2014 \u043D\u0435\u043F\u043E\u043D\u044F\u0442\u0430\u044F \u041C\u0430\u0442\u044C <em>(m\u0101t\u1E5Bk\u0101)</em></p></div><div class="stanza"><a href="#s1.5" id="s1.5" class="num">1.5</a><p class="sans">\u0909\u0926\u094D\u092F\u092E\u094B \u092D\u0948\u0930\u0935\u0903 \u0965\u096B\u0965</p><p class="trans">Udyamo bhairava\u1E25 \u09655\u0965</p><p>\u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430 --\u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0438\u0439-- <em>(bhairava\u1E25)</em> \u2014 [\u044D\u0442\u043E] \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F \u0432\u0441\u043F\u044B\u0448\u043A\u0430, \u0438\u043B\u0438 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(udyama\u1E25)</em></p></div><div class="stanza"><a href="#s1.6" id="s1.6" class="num">1.6</a><p class="sans">\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0935\u093F\u0936\u094D\u0935\u0938\u0902\u0939\u093E\u0930\u0903 \u0965\u096C\u0965</p><p class="trans">\u015Aakticakrasandh\u0101ne vi\u015Bvasa\u1E41h\u0101ra\u1E25 \u09656\u0965</p><p>\u041F\u0440\u0438 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0438 <em>(sandh\u0101ne)</em> \u0441 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em> <em>(\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442)</em> \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em></p></div><div class="stanza"><a href="#s1.7" id="s1.7" class="num">1.7</a><p class="sans">\u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u0938\u0941\u0937\u0941\u092A\u094D\u0924\u092D\u0947\u0926\u0947 \u0924\u0941\u0930\u094D\u092F\u093E\u092D\u094B\u0917\u0938\u092E\u094D\u092D\u0935\u0903 \u0965\u096D\u0965</p><p class="trans">J\u0101gratsvapnasu\u1E63uptabhede tury\u0101bhogasambhava\u1E25 \u09657\u0965</p><p>[\u0414\u0430\u0436\u0435] \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0437\u043D\u044B\u0445 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] <em>(bhede)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em>, \u0441\u043E\u043D <em>(svapna)</em> \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D <em>(su\u1E63upta)</em>, \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442 <em>(sambhava\u1E25)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(\u0101bhoga)</em> \u0427\u0435\u0442\u0432\u0451\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(turya)</em></p></div><div class="stanza"><a href="#s1.8" id="s1.8" class="num">1.8</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u0902 \u091C\u093E\u0917\u094D\u0930\u0924\u094D \u0965\u096E\u0965</p><p class="trans">J\xF1\u0101na\u1E41 j\u0101grat \u09658\u0965</p><p>\u0417\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u0435\u0441\u0442\u044C] \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em></p></div><div class="stanza"><a href="#s1.9" id="s1.9" class="num">1.9</a><p class="sans">\u0938\u094D\u0935\u092A\u094D\u0928\u094B \u0935\u093F\u0915\u0932\u094D\u092A\u093E\u0903 \u0965\u096F\u0965</p><p class="trans">Svapno vikalp\u0101\u1E25 \u09659\u0965</p><p>\u0421\u043E\u043D <em>(svapna\u1E25)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u043C\u044B\u0441\u043B\u0435\u0439 \u0438 \u0438\u0434\u0435\u0439 <em>(vikalp\u0101\u1E25)</em></p></div><div class="stanza"><a href="#s1.10" id="s1.10" class="num">1.10</a><p class="sans">\u0905\u0935\u093F\u0935\u0947\u0915\u094B \u092E\u093E\u092F\u093E\u0938\u094C\u0937\u0941\u092A\u094D\u0924\u092E\u094D \u0965\u0967\u0966\u0965</p><p class="trans">Aviveko m\u0101y\u0101sau\u1E63uptam \u096510\u0965</p><p>\u041D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(aviveka\u1E25)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u043C \u0441\u043D\u043E\u043C <em>(sau\u1E63uptam)</em> \u043C\u0430\u0439\u0438 --\u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430-- <em>(m\u0101y\u0101)</em></p></div><div class="stanza"><a href="#s1.11" id="s1.11" class="num">1.11</a><p class="sans">\u0924\u094D\u0930\u093F\u0924\u092F\u092D\u094B\u0915\u094D\u0924\u093E \u0935\u0940\u0930\u0947\u0936\u0903 \u0965\u0967\u0967\u0965</p><p class="trans">Tritayabhokt\u0101 v\u012Bre\u015Ba\u1E25 \u096511\u0965</p><p>\u0422\u043E\u0442 \u0445\u043E\u0437\u044F\u0438\u043D <em>(\u012B\u015Ba\u1E25)</em> <em>(\u0441\u0432\u043E\u0438\u0445)</em> \u0447\u0443\u0432\u0441\u0442\u0432 <em>(v\u012Bra)</em>, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C <em>(\u0101bhoga)</em>, \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C,] <em>(bhokt\u0101)</em> \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0442\u0440\u0438\u0430\u0434\u044B [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D] <em>(tritaya)</em></p></div><div class="stanza"><a href="#s1.12" id="s1.12" class="num">1.12</a><p class="sans">\u0935\u093F\u0938\u094D\u092E\u092F\u094B \u092F\u094B\u0917\u092D\u0942\u092E\u093F\u0915\u093E\u0903 \u0965\u0967\u0968\u0965</p><p class="trans">Vismayo yogabh\u016Bmik\u0101\u1E25 \u096512\u0965</p><p>\u0421\u0442\u0430\u0434\u0438\u0438 <em>(bh\u016Bmik\u0101\u1E25)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em> [\u044F\u0432\u043B\u044F\u044E\u0442 \u0441\u043E\u0431\u043E\u0439] \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0447\u0443\u0434\u043E <em>(vismaya\u1E25)</em></p></div><div class="stanza"><a href="#s1.13" id="s1.13" class="num">1.13</a><p class="sans">\u0907\u091A\u094D\u091B\u093E\u0936\u0915\u094D\u0924\u093F\u0930\u0941\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940 \u0965\u0967\u0969\u0965</p><p class="trans">Icch\u0101\u015Baktirum\u0101 kum\u0101r\u012B \u096513\u0965</p><p>\u0421\u0438\u043B\u0430 \u0432\u043E\u043B\u0438 <em>(icch\u0101 \u015Bakti\u1E25)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430] \u2014 \xAB\u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 \u0428\u0438\u0432\u044B\xBB <em>(um\u0101)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C] \u041A\u0443\u043C\u0430\u0440\u0438 <em>(kum\u0101r\u012B)</em></p></div><div class="stanza"><a href="#s1.14" id="s1.14" class="num">1.14</a><p class="sans">\u0926\u0943\u0936\u094D\u092F\u0902 \u0936\u0930\u0940\u0930\u092E\u094D \u0965\u0967\u096A\u0965</p><p class="trans">D\u1E5B\u015Bya\u1E41 \u015Bar\u012Bram \u096514\u0965</p><p>\u0412\u0441\u0435 \u044F\u0432\u043B\u0435\u043D\u0438\u044F [\u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435] <em>(d\u1E5B\u015Byam)</em> \u2014 \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bram)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430]</p></div><div class="stanza"><a href="#s1.15" id="s1.15" class="num">1.15</a><p class="sans">\u0939\u0943\u0926\u092F\u0947 \u091A\u093F\u0924\u094D\u0924\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0938\u094D\u0935\u093E\u092A\u0926\u0930\u094D\u0936\u0928\u092E\u094D \u0965\u0967\u096B\u0965</p><p class="trans">H\u1E5Bdaye cittasa\u1E45gha\u1E6D\u1E6D\u0101dd\u1E5B\u015Byasv\u0101padar\u015Banam \u096515\u0965</p><p>\u0427\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sa\u1E45gha\u1E6D\u1E6D\u0101t)</em> \u0443\u043C\u0430 <em>(citta)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(h\u1E5Bdaye)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> [\u0432\u0441\u0435\u0445] \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u0432 [\u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445] <em>(d\u1E5B\u015Bya)</em>, [\u0434\u0430\u0436\u0435] \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(sv\u0101pa)</em>, [\u0432 \u0438\u0445 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u043C \u0432\u0438\u0434\u0435]</p></div><div class="stanza"><a href="#s1.16" id="s1.16" class="num">1.16</a><p class="sans">\u0936\u0941\u0926\u094D\u0927\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0926\u094D\u0935\u093E\u092A\u0936\u0941\u0936\u0915\u094D\u0924\u093F\u0903 \u0965\u0967\u096C\u0965</p><p class="trans">\u015Auddhatattvasandh\u0101n\u0101dv\u0101pa\u015Bu\u015Bakti\u1E25 \u096516\u0965</p><p>\u0418\u043B\u0438 \u0436\u0435 <em>(v\u0101)</em> \u0447\u0435\u0440\u0435\u0437 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sandh\u0101n\u0101t)</em> \u0441 \u0427\u0438\u0441\u0442\u044B\u043C <em>(\u015Buddha)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C <em>(tattva)</em>, [\u0419\u043E\u0433 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0442\u0435\u043C, \u0432 \u043A\u043E\u043C] [\u0441\u043A\u043E\u0432\u044B\u0432\u0430\u044E\u0449\u0430\u044F] \u0441\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, [\u043F\u0440\u0438\u0441\u0443\u0449\u0430\u044F] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443 <em>(pa\u015Bu)</em>, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(a)</em></p></div><div class="stanza"><a href="#s1.17" id="s1.17" class="num">1.17</a><p class="sans">\u0935\u093F\u0924\u0930\u094D\u0915 \u0906\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0965\u0967\u096D\u0965</p><p class="trans">Vitarka \u0101tmaj\xF1\u0101nam \u096517\u0965</p><p>\u0422\u0432\u0451\u0440\u0434\u043E\u0435 \u0438 \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vitarka\u1E25)</em> [\xAB\u042F \u2014 \u0428\u0438\u0432\u0430\xBB, \u0435\u0441\u0442\u044C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em></p></div><div class="stanza"><a href="#s1.18" id="s1.18" class="num">1.18</a><p class="sans">\u0932\u094B\u0915\u093E\u0928\u0928\u094D\u0926\u0903 \u0938\u092E\u093E\u0927\u093F\u0938\u0941\u0916\u092E\u094D \u0965\u0967\u096E\u0965</p><p class="trans">Lok\u0101nanda\u1E25 sam\u0101dhisukham \u096518\u0965</p><p>\u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0419\u043E\u0433 \u043E\u0449\u0443\u0449\u0430\u0435\u0442 \u043A\u0430\u043A \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439] <em>(\u0101nanda\u1E25)</em> \u043C\u0438\u0440, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(loka)</em>, \u2014 [\u044D\u0442\u043E \u0435\u0433\u043E] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(sukham)</em> \u0432 \u0441\u0430\u043C\u0430\u0434\u0445\u0438 <em>(sam\u0101dhi)</em></p></div><div class="stanza"><a href="#s1.19" id="s1.19" class="num">1.19</a><p class="sans">\u0936\u0915\u094D\u0924\u093F\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0936\u0930\u0940\u0930\u094B\u0924\u094D\u092A\u0924\u094D\u0924\u093F\u0903 \u0965\u0967\u096F\u0965</p><p class="trans">\u015Aaktisandh\u0101ne \u015Bar\u012Brotpatti\u1E25 \u096519\u0965</p><p>\u041F\u0440\u0438 \u0441\u043E\u044E\u0437\u0435 <em>(sandh\u0101ne)</em> \u0441 \u0421\u0438\u043B\u043E\u0439 [\u0412\u043E\u043B\u0438] <em>(\u015Bakti)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 <em>(utpatti\u1E25)</em> \u0442\u0435\u043B <em>(\u015Bar\u012Bra)</em> [\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E \u0419\u043E\u0433\u0430]</p></div><div class="stanza"><a href="#s1.20" id="s1.20" class="num">1.20</a><p class="sans">\u092D\u0942\u0924\u0938\u0928\u094D\u0927\u093E\u0928\u092D\u0942\u0924\u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u0935\u093F\u0936\u094D\u0935\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u093E\u0903 \u0965\u0968\u0966\u0965</p><p class="trans">Bh\u016Btasandh\u0101nabh\u016Btap\u1E5Bthaktvavi\u015Bvasa\u1E45gha\u1E6D\u1E6D\u0101\u1E25 \u096520\u0965</p><p>[\u0414\u0440\u0443\u0433\u0438\u0435 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430 \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 \u0441\u0438\u043B\u044B] \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(sandh\u0101na)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439 <em>(bh\u016Bta)</em>, [\u0441\u0438\u043B\u044B] \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F <em>(p\u1E5Bthaktva)</em> \u0432\u0441\u0435\u0445 \u0438\u0445 --\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439-- <em>(bh\u016Bta)</em> [\u0438 \u0441\u0438\u043B\u044B] \u0432\u043E\u0441\u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F --sa\u1E45gha\u1E6D\u1E6Da-- <em>(sa\u1E45gha\u1E6D\u1E6D\u0101\u1E25)</em> \u0432\u0441\u0435\u0433\u043E <em>(vi\u015Bva)</em>, [\u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C \u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C]</p></div><div class="stanza"><a href="#s1.21" id="s1.21" class="num">1.21</a><p class="sans">\u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u094B\u0926\u092F\u093E\u091A\u094D\u091A\u0915\u094D\u0930\u0947\u0936\u0924\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0903 \u0965\u0968\u0967\u0965</p><p class="trans">\u015Auddhavidyoday\u0101ccakre\u015Batvasiddhi\u1E25 \u096521\u0965</p><p>\u041F\u0440\u0438 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 <em>(uday\u0101t)</em> \u0428\u0443\u0434\u0434\u0445\u0430\u0432\u0438\u0434\u044C\u0438 <em>(\u015Buddhavidy\u0101)</em>, [\u0434\u043B\u044F \u0419\u043E\u0433\u0430 \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442] \u043F\u043E\u043B\u043D\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(siddhi\u1E25)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0430 <em>(\u012B\u015Batva)</em> \u043D\u0430\u0434 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0441\u0438\u043B <em>(cakra)</em></p></div><div class="stanza"><a href="#s1.22" id="s1.22" class="num">1.22</a><p class="sans">\u092E\u0939\u093E\u0939\u094D\u0930\u0926\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u093E\u0928\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0928\u0941\u092D\u0935\u0903 \u0965\u0968\u0968\u0965</p><p class="trans">Mah\u0101hrad\u0101nusandh\u0101n\u0101nmantrav\u012Bry\u0101nubhava\u1E25 \u096522\u0965</p><p>\u0421\u043E\u0435\u0434\u0438\u043D\u044F\u044F\u0441\u044C <em>(anusandh\u0101n\u0101t)</em> \u0441 \u0412\u0435\u043B\u0438\u043A\u0438\u043C <em>(mah\u0101)</em> \u041E\u0437\u0435\u0440\u043E\u043C <em>(hrada)</em>, <em>(\u0419\u043E\u0433 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442)</em> \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043E\u043F\u044B\u0442 <em>(anubhava\u1E25)</em> \u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 --\u0441\u0438\u043B\u044B, \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0438-- <em>(v\u012Brya)</em> [\u0432\u0441\u0435\u0445] \u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em></p></div><h2 id="\u0447\u0430\u0441\u0442\u044C-\u0432\u0442\u043E\u0440\u0430\u044F" tabindex="-1">\u0427\u0430\u0441\u0442\u044C \u0432\u0442\u043E\u0440\u0430\u044F <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-\u0432\u0442\u043E\u0440\u0430\u044F" aria-hidden="true">#</a></h2><p class="sans">\u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F</p><p class="trans">\u015A\u0101ktop\u0101ya</p><p>\u041C\u0435\u0442\u043E\u0434, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043D\u0430 \u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F \u0428\u0430\u043A\u0442\u0438</p><div class="stanza"><a href="#s2.1" id="s2.1" class="num">2.1</a><p class="sans">\u091A\u093F\u0924\u094D\u0924\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0903 \u0965\u0967\u0965</p><p class="trans">Citta\u1E41 mantra\u1E25 \u09651\u0965</p><p>\u0423\u043C <em>(\u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043E \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438,)</em> <em>(cittam)</em> [\u0435\u0441\u0442\u044C] \u041C\u0430\u043D\u0442\u0440\u0430 <em>(mantra\u1E25)</em></p></div><div class="stanza"><a href="#s2.2" id="s2.2" class="num">2.2</a><p class="sans">\u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0903 \u0938\u093E\u0927\u0915\u0903 \u0965\u0968\u0965</p><p class="trans">Prayatna\u1E25 s\u0101dhaka\u1E25 \u09652\u0965</p><p>[\u0420\u044C\u044F\u043D\u043E\u0435 \u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435] \u0443\u0441\u0438\u043B\u0438\u0435 <em>(prayatna\u1E25)</em> \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0443\u0441\u043F\u0435\u0445\u0430 <em>(s\u0101dhaka\u1E25)</em></p></div><div class="stanza"><a href="#s2.3" id="s2.3" class="num">2.3</a><p class="sans">\u0935\u093F\u0926\u094D\u092F\u093E\u0936\u0930\u0940\u0930\u0938\u0924\u094D\u0924\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u0930\u0939\u0938\u094D\u092F\u092E\u094D \u0965\u0969\u0965</p><p class="trans">Vidy\u0101\u015Bar\u012Brasatt\u0101 mantrarahasyam \u09653\u0965</p><p>[\u0421\u0438\u044F\u044E\u0449\u0430\u044F] \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C [\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u041E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u042F] <em>(satt\u0101)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0441\u043B\u043E\u0432], \u0447\u044C\u0435\u0439 \u0441\u0443\u0442\u044C\u044E <em>(\u015Bar\u012Bra)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u043D\u0430\u043D\u0438\u0435 [\u0432\u044B\u0441\u0448\u0435\u0439 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438] <em>(vidy\u0101)</em>, \u2014 \u0441\u0435\u043A\u0440\u0435\u0442 <em>(rahasyam)</em> \u041C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em></p></div><div class="stanza"><a href="#s2.4" id="s2.4" class="num">2.4</a><p class="sans">\u0917\u0930\u094D\u092D\u0947 \u091A\u093F\u0924\u094D\u0924\u0935\u093F\u0915\u093E\u0938\u094B\u093D\u0935\u093F\u0936\u093F\u0937\u094D\u091F\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u092A\u094D\u0928\u0903 \u0965\u096A\u0965</p><p class="trans">Garbhe cittavik\u0101so&#39;vi\u015Bi\u1E63\u1E6Davidy\u0101svapna\u1E25 \u09654\u0965</p><p>\u0423\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0451\u043D\u043D\u043E\u0441\u0442\u044C <em>(vik\u0101sa\u1E25)</em> \u0443\u043C\u0430 <em>(citta)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438] \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438 <em>(garbhe)</em> \u2014 [\u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C] \u0441\u043E\u043D <em>(svapna\u1E25)</em>, [\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043D\u0430] \u043D\u0438\u0437\u0448\u0435\u043C <em>(avi\u015Bi\u1E63\u1E6Da)</em> \u0437\u043D\u0430\u043D\u0438\u0438 <em>(vidy\u0101)</em></p></div><div class="stanza"><a href="#s2.5" id="s2.5" class="num">2.5</a><p class="sans">\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u092E\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u0938\u094D\u0935\u093E\u092D\u093E\u0935\u093F\u0915\u0947 \u0916\u0947\u091A\u0930\u0940 \u0936\u093F\u0935\u093E\u0935\u0938\u094D\u0925\u093E \u0965\u096B\u0965</p><p class="trans">Vidy\u0101samutth\u0101ne sv\u0101bh\u0101vike khecar\u012B \u015Biv\u0101vasth\u0101 \u09655\u0965</p><p>\u041F\u0440\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u043C <em>(sv\u0101bh\u0101vike)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 <em>(samutth\u0101ne)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em>, \u0432 \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 <em>(khecar\u012B)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(avasth\u0101)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em></p></div><div class="stanza"><a href="#s2.6" id="s2.6" class="num">2.6</a><p class="sans">\u0917\u0941\u0930\u0941\u0930\u0941\u092A\u093E\u092F\u0903 \u0965\u096C\u0965</p><p class="trans">Gururup\u0101ya\u1E25 \u09656\u0965</p><p>\u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(up\u0101ya\u1E25)</em></p></div><div class="stanza"><a href="#s2.7" id="s2.7" class="num">2.7</a><p class="sans">\u092E\u093E\u0924\u0943\u0915\u093E\u091A\u0915\u094D\u0930\u0938\u092E\u094D\u092C\u094B\u0927\u0903 \u0965\u096D\u0965</p><p class="trans">M\u0101t\u1E5Bk\u0101cakrasambodha\u1E25 \u09657\u0965</p><p>[\u041E\u0442 \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E\u0433\u043E \u0413\u0443\u0440\u0443 \u043D\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u0438\u0435 <em>(sambodha\u1E25)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0431\u0443\u043A\u0432 <em>(m\u0101t\u1E5Bk\u0101)</em></p></div><div class="stanza"><a href="#s2.8" id="s2.8" class="num">2.8</a><p class="sans">\u0936\u0930\u0940\u0930\u0902 \u0939\u0935\u093F\u0903 \u0965\u096E\u0965</p><p class="trans">\u015Aar\u012Bra\u1E41 havi\u1E25 \u09658\u0965</p><p>\u0422\u0435\u043B\u043E [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0431\u044B\u043B\u043E \u0438\u0437\u043B\u0438\u0442\u043E \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u0438\u0435,] <em>(\u015Bar\u012Bram)</em> [\u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432] \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435 <em>(havi\u1E25)</em></p></div><div class="stanza"><a href="#s2.9" id="s2.9" class="num">2.9</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u092E\u0928\u094D\u0928\u092E\u094D \u0965\u096F\u0965</p><p class="trans">J\xF1\u0101namannam \u09659\u0965</p><p>[\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0438\u0449\u0435\u0439 <em>(annam)</em></p></div><div class="stanza"><a href="#s2.10" id="s2.10" class="num">2.10</a><p class="sans">\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u0902\u0939\u093E\u0930\u0947 \u0924\u0926\u0941\u0924\u094D\u0925\u0938\u094D\u0935\u092A\u094D\u0928\u0926\u0930\u094D\u0936\u0928\u092E\u094D \u0965\u0967\u0966\u0965</p><p class="trans">Vidy\u0101sa\u1E41h\u0101re tadutthasvapnadar\u015Banam \u096510\u0965</p><p>\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(sa\u1E41h\u0101re)</em> [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> \u043A\u043E\u043B\u0435\u0431\u0430\u043D\u0438\u0439 \u0443\u043C\u0430 [\u043A\u0430\u043A \u0432\u043E \u0441\u043D\u0435] <em>(svapna)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 <em>(uttha)</em> \u0438\u0437-\u0437\u0430 \u043D\u0435\u0433\u043E <em>(tad)</em> [\u0438\u0437-\u0437\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F]</p></div><h2 id="\u0447\u0430\u0441\u0442\u044C-\u0442\u0440\u0435\u0442\u044C\u044F" tabindex="-1">\u0427\u0430\u0441\u0442\u044C \u0442\u0440\u0435\u0442\u044C\u044F <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-\u0442\u0440\u0435\u0442\u044C\u044F" aria-hidden="true">#</a></h2><p class="sans">\u0906\u0923\u0935\u094B\u092A\u093E\u092F</p><p class="trans">\u0100\u1E47avop\u0101ya</p><p>\u041C\u0435\u0442\u043E\u0434, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043D\u0430 \u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F \u0430\u1E47u, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430</p><div class="stanza"><a href="#s3.1" id="s3.1" class="num">3.1</a><p class="sans">\u0906\u0924\u094D\u092E\u093E \u091A\u093F\u0924\u094D\u0924\u092E\u094D \u0965\u0967\u0965</p><p class="trans">\u0100tm\u0101 cittam \u09651\u0965</p><p>\u0418\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u042F <em>(\u0101tm\u0101)</em> [\u0435\u0441\u0442\u044C] \u0443\u043C <em>(cittam)</em></p></div><div class="stanza"><a href="#s3.2" id="s3.2" class="num">3.2</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0928\u094D\u0927\u0903 \u0965\u0968\u0965</p><p class="trans">J\xF1\u0101na\u1E41 bandha\u1E25 \u09652\u0965</p><p>[\u041F\u043E\u0440\u043E\u0436\u0434\u0451\u043D\u043D\u043E\u0435 \u0443\u043C\u043E\u043C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u2014 \u0440\u0430\u0431\u0441\u0442\u0432\u043E <em>(bandha\u1E25)</em></p></div><div class="stanza"><a href="#s3.3" id="s3.3" class="num">3.3</a><p class="sans">\u0915\u0932\u093E\u0926\u0940\u0928\u093E\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0928\u093E\u092E\u0935\u093F\u0935\u0947\u0915\u094B \u092E\u093E\u092F\u093E \u0965\u0969\u0965</p><p class="trans">Kal\u0101d\u012Bn\u0101\u1E41 tattv\u0101n\u0101maviveko m\u0101y\u0101 \u09653\u0965</p><p>\u041D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 <em>(aviveka\u1E25)</em> [\u0442\u0430\u043A\u0438\u0445] \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 <em>(tattv\u0101n\u0101m)</em>, \u043A\u0430\u043A \u043A\u0430\u043B\u0430 <em>(kal\u0101)</em> \u0438 \u0442.\u0434. <em>(\u0101d\u012Bn\u0101m)</em>, [\u0435\u0441\u0442\u044C] \u043C\u0430\u0439\u044F <em>(m\u0101y\u0101)</em></p></div><div class="stanza"><a href="#s3.4" id="s3.4" class="num">3.4</a><p class="sans">\u0936\u0930\u0940\u0930\u0947 \u0938\u0902\u0939\u093E\u0930\u0903 \u0915\u0932\u093E\u0928\u093E\u092E\u094D \u0965\u096A\u0965</p><p class="trans">\u015Aar\u012Bre sa\u1E41h\u0101ra\u1E25 kal\u0101n\u0101m \u09654\u0965</p><p>\u0420\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0447\u0430\u0441\u0442\u0435\u0439 <em>(kal\u0101n\u0101m)</em> --\u0442\u0430\u0442\u0442\u0432, \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F-- \u0432 \u0442\u0435\u043B\u0435 [\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u043C, \u0442\u043E\u043D\u043A\u043E\u043C \u0438 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u043C] <em>(\u015Bar\u012Bre)</em> [\u0434\u043E\u043B\u0436\u043D\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E bh\u0101van\u0101, \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F]</p></div><div class="stanza"><a href="#s3.5" id="s3.5" class="num">3.5</a><p class="sans">\u0928\u093E\u0921\u0940\u0938\u0902\u0939\u093E\u0930\u092D\u0942\u0924\u091C\u092F\u092D\u0942\u0924\u0915\u0948\u0935\u0932\u094D\u092F\u092D\u0942\u0924\u092A\u0943\u0925\u0915\u094D\u0924\u094D\u0935\u093E\u0928\u093F \u0965\u096B\u0965</p><p class="trans">N\u0101\u1E0D\u012Bsa\u1E41h\u0101rabh\u016Btajayabh\u016Btakaivalyabh\u016Btap\u1E5Bthaktv\u0101ni \u09655\u0965</p><p>[\u0419\u043E\u0433 \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u043E\u0441\u0442\u0438\u0447\u044C] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438] <em>(sa\u1E41h\u0101ra)</em> \u0432 \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(n\u0101\u1E0D\u012B)</em>, \u043F\u043E\u0431\u0435\u0434\u044B <em>(jaya)</em> \u043D\u0430\u0434 \u0433\u0440\u0443\u0431\u044B\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 <em>(bh\u016Bta)</em>, \u043E\u0442\u043E\u0437\u0432\u0430\u043D\u0438\u044F [\u0441\u0432\u043E\u0435\u0433\u043E \u0443\u043C\u0430] <em>(kaivalya)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> [\u0438] \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u0438\u044F --p\u1E5Bthaktva-- <em>(p\u1E5Bthaktv\u0101ni)</em> \u043E\u0442 \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> [\u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E bh\u0101van\u0101, \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F]</p></div><div class="stanza"><a href="#s3.6" id="s3.6" class="num">3.6</a><p class="sans">\u092E\u094B\u0939\u093E\u0935\u0930\u0923\u093E\u0924\u094D\u0938\u093F\u0926\u094D\u0927\u093F\u0903 \u0965\u096C\u0965</p><p class="trans">Moh\u0101vara\u1E47\u0101tsiddhi\u1E25 \u09656\u0965</p><p>\u0421\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 <em>(siddhi\u1E25)</em> [\u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0438\u0437-\u0437\u0430 \u0432\u0443\u0430\u043B\u0438 <em>(\u0101vara\u1E47\u0101t)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442] \u043C\u0430\u0439\u044F, \u0438\u043B\u0438 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E <em>(moha)</em></p></div><div class="stanza"><a href="#s3.7" id="s3.7" class="num">3.7</a><p class="sans">\u092E\u094B\u0939\u091C\u092F\u093E\u0926\u0928\u0928\u094D\u0924\u093E\u092D\u094B\u0917\u093E\u0924\u094D\u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u093E\u091C\u092F\u0903 \u0965\u096D\u0965</p><p class="trans">Mohajay\u0101danant\u0101bhog\u0101tsahajavidy\u0101jaya\u1E25 \u09657\u0965</p><p>[\u0419\u043E\u0433 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442] \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044F <em>(jaya\u1E25)</em> \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sahaja)</em> \u0417\u043D\u0430\u043D\u0438\u0435\u043C <em>(vidy\u0101)</em> \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u0443\u044E \u043F\u043E\u0431\u0435\u0434\u0443 <em>(jay\u0101t anant\u0101bhog\u0101t)</em> \u043D\u0430\u0434 \u043C\u0430\u0439\u0435\u0439, \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(moha)</em></p></div><div class="stanza"><a href="#s3.8" id="s3.8" class="num">3.8</a><p class="sans">\u091C\u093E\u0917\u094D\u0930\u0926\u094D\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u0915\u0930\u0903 \u0965\u096E\u0965</p><p class="trans">J\u0101graddvit\u012Byakara\u1E25 \u09658\u0965</p><p>[\u0419\u043E\u0433, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 Sahajavidy\u0101, \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F,] \u0431\u043E\u0434\u0440 \u0438 \u0431\u0434\u0438\u0442\u0435\u043B\u0435\u043D <em>(j\u0101grat)</em>, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] \u0432\u0442\u043E\u0440\u043E\u0439 [\u0442\u043E \u0435\u0441\u0442\u044C \u043C\u0438\u0440] <em>(dvit\u012Bya)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432 \u0432\u0438\u0434\u0435 [\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E] \u0441\u0438\u044F\u043D\u0438\u044F <em>(kara\u1E25)</em></p></div><div class="stanza"><a href="#s3.9" id="s3.9" class="num">3.9</a><p class="sans">\u0928\u0930\u094D\u0924\u0915 \u0906\u0924\u094D\u092E\u093E \u0965\u096F\u0965</p><p class="trans">Nartaka \u0101tm\u0101 \u09659\u0965</p><p>[\u042D\u0442\u043E\u0442 \u0419\u043E\u0433 \u2014] \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tm\u0101)</em> [\u0432 \u0432\u0438\u0434\u0435 \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C] \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u043A\u0442\u0451\u0440\u0430 <em>(nartaka\u1E25)</em></p></div><div class="stanza"><a href="#s3.10" id="s3.10" class="num">3.10</a><p class="sans">\u0930\u0919\u094D\u0917\u094B\u093D\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E \u0965\u0967\u0966\u0965</p><p class="trans">Ra\u1E45go&#39;ntar\u0101tm\u0101 \u096510\u0965</p><p>\u0421\u0446\u0435\u043D\u043E\u0439 [\u044D\u0442\u043E\u043C\u0443 \u041D\u0430\u0440\u0442\u0430\u043A\u0435, \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u043C\u0443 \u0430\u043A\u0442\u0451\u0440\u0443] <em>(ra\u1E45ga\u1E25)</em> [\u0441\u043B\u0443\u0436\u0438\u0442 \u0435\u0433\u043E] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F <em>(antar)</em> \u0434\u0443\u0448\u0430 <em>(\u0101tm\u0101)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438 \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B]</p></div><div class="stanza"><a href="#s3.11" id="s3.11" class="num">3.11</a><p class="sans">\u092A\u094D\u0930\u0947\u0915\u094D\u0937\u0915\u093E\u0923\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u0965\u0967\u0967\u0965</p><p class="trans">Prek\u1E63ak\u0101\u1E47\u012Bndriy\u0101\u1E47i \u096511\u0965</p><p>\u0427\u0443\u0432\u0441\u0442\u0432\u0430 [\u044D\u0442\u043E\u0433\u043E \u041D\u0430\u0440\u0442\u0430\u043A\u0438, \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u043A\u0442\u0451\u0440\u0430,] <em>(indriy\u0101\u1E47i)</em> [\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F] \u0437\u0440\u0438\u0442\u0435\u043B\u044F\u043C\u0438 [\u0435\u0433\u043E \u0438\u0433\u0440\u044B] <em>(prek\u1E63ak\u0101\u1E47i)</em></p></div><div class="stanza"><a href="#s3.12" id="s3.12" class="num">3.12</a><p class="sans">\u0927\u0940\u0935\u0936\u093E\u0924\u094D\u0938\u0924\u094D\u0924\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0903 \u0965\u0967\u0968\u0965</p><p class="trans">Dh\u012Bva\u015B\u0101tsattvasiddhi\u1E25 \u096512\u0965</p><p>\u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E <em>(va\u015B\u0101t)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0443\u043C\u0430 <em>(dh\u012B)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(siddhi\u1E25)</em> \u0442\u043E\u043D\u043A\u043E\u0439, \u043C\u0435\u0440\u0446\u0430\u044E\u0449\u0435\u0439, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u042F <em>(sattva)</em></p></div><div class="stanza"><a href="#s3.13" id="s3.13" class="num">3.13</a><p class="sans">\u0938\u093F\u0926\u094D\u0927\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u092D\u093E\u0935\u0903 \u0965\u0967\u0969\u0965</p><p class="trans">Siddha\u1E25 svatantrabh\u0101va\u1E25 \u096513\u0965</p><p>\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(svatantra)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E <em>(siddha\u1E25)</em></p></div><div class="stanza"><a href="#s3.14" id="s3.14" class="num">3.14</a><p class="sans">\u092F\u0925\u093E \u0924\u0924\u094D\u0930 \u0924\u0925\u093E\u0928\u094D\u092F\u0924\u094D\u0930 \u0965\u0967\u096A\u0965</p><p class="trans">Yath\u0101 tatra tath\u0101nyatra \u096514\u0965</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0442\u0430\u043C <em>(tatra)</em>, \u0442\u0430\u043A <em>(tath\u0101)</em> \u0438 \u0433\u0434\u0435-\u043B\u0438\u0431\u043E \u0435\u0449\u0451 <em>(anyatra)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u0439 \u0419\u043E\u0433 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0421\u0432\u043E\u0431\u043E\u0434\u0443 \u043A\u0430\u043A \u0432 \u0441\u0432\u043E\u0451\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u0442\u0430\u043A \u0438 \u043B\u044E\u0431\u043E\u043C \u0434\u0440\u0443\u0433\u043E\u043C \u043C\u0435\u0441\u0442\u0435]</p></div><div class="stanza"><a href="#s3.15" id="s3.15" class="num">3.15</a><p class="sans">\u092C\u0940\u091C\u093E\u0935\u0927\u093E\u0928\u092E\u094D \u0965\u0967\u096B\u0965</p><p class="trans">B\u012Bj\u0101vadh\u0101nam \u096515\u0965</p><p>[\u042D\u0442\u043E\u0442 \u0419\u043E\u0433 \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0444\u043E\u043A\u0443\u0441\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432\u0441\u0451 \u0441\u0432\u043E\u0451] \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 <em>(avadh\u0101nam)</em> \u043D\u0430 \u0421\u0435\u043C\u0435\u043D\u0438 [\u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u0439 \u0428\u0430\u043A\u0442\u0438, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438 \u042F, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u0432\u0441\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E] <em>(b\u012Bja)</em></p></div><div class="stanza"><a href="#s3.16" id="s3.16" class="num">3.16</a><p class="sans">\u0906\u0938\u0928\u0938\u094D\u0925\u0903 \u0938\u0941\u0916\u0902 \u0939\u094D\u0930\u0926\u0947 \u0928\u093F\u092E\u091C\u094D\u091C\u0924\u093F \u0965\u0967\u096C\u0965</p><p class="trans">\u0100sanastha\u1E25 sukha\u1E41 hrade nimajjati \u096516\u0965</p><p>\u0423\u043A\u043E\u0440\u0435\u043D\u0438\u0432\u0448\u0438\u0441\u044C <em>(stha\u1E25)</em> \u0432 \u0441\u0438\u043B\u0435 \u0412\u044B\u0441\u0448\u0435\u0439 \u0428\u0430\u043A\u0442\u0438, [\u0432 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438 \u042F, \u0441\u043B\u0443\u0436\u0430\u0449\u0435\u043C\u0443 \u0435\u043C\u0443] \u0441\u0438\u0434\u0435\u043D\u044C\u0435\u043C, <em>(\u0101sana)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u044B\u0439 \u0419\u043E\u0433] \u0441 \u043B\u0451\u0433\u043A\u043E\u0441\u0442\u044C\u044E <em>(sukham)</em> \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F <em>(nimajjati)</em> \u0432 \u041E\u0437\u0435\u0440\u043E [\u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u043E\u0433\u043E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(hrade)</em></p></div><div class="stanza"><a href="#s3.17" id="s3.17" class="num">3.17</a><p class="sans">\u0938\u094D\u0935\u092E\u093E\u0924\u094D\u0930\u093E\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F \u0965\u0967\u096D\u0965</p><p class="trans">Svam\u0101tr\u0101nirm\u0101\u1E47am\u0101p\u0101dayati \u096517\u0965</p><p>[\u042D\u0442\u043E\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u0439 \u0419\u043E\u0433 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D] \u0441\u043E\u0437\u0434\u0430\u0442\u044C <em>(nirm\u0101\u1E47am \u0101p\u0101dayati)</em> [\u043B\u044E\u0431\u0443\u044E \u0444\u043E\u0440\u043C\u0443 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E] \u043C\u0435\u0440\u0435 \u0438\u043B\u0438 \u0430\u0441\u043F\u0435\u043A\u0442\u0443 \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u0441\u043B\u0443\u0436\u0430\u0449\u0435\u0433\u043E \u0435\u043C\u0443 \u0101sana, \u0441\u0438\u0434\u0435\u043D\u044C\u0435\u043C] <em>(svam\u0101tr\u0101)</em></p></div><div class="stanza"><a href="#s3.18" id="s3.18" class="num">3.18</a><p class="sans">\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u093F\u0928\u093E\u0936\u0947 \u091C\u0928\u094D\u092E\u0935\u093F\u0928\u093E\u0936\u0903 \u0965\u0967\u096E\u0965</p><p class="trans">Vidy\u0101vin\u0101\u015Be janmavin\u0101\u015Ba\u1E25 \u096518\u0965</p><p>\u041F\u043E\u043A\u0443\u0434\u0430 Sahajavidy\u0101 \u0438\u043B\u0438 \u015Auddhavidy\u0101 [\u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435] <em>(vidy\u0101)</em> \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(avin\u0101\u015Be)</em>, [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043D\u043E\u0432\u043E\u0433\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 [\u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430] <em>(vin\u0101\u015Ba\u1E25)</em></p></div><div class="stanza"><a href="#s3.19" id="s3.19" class="num">3.19</a><p class="sans">\u0915\u0935\u0930\u094D\u0917\u093E\u0926\u093F\u0937\u0941 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u094D\u092F\u093E\u0903 \u092A\u0936\u0941\u092E\u093E\u0924\u0930\u0903 \u0965\u0967\u096F\u0965</p><p class="trans">Kavarg\u0101di\u1E63u m\u0101he\u015Bvary\u0101dy\u0101\u1E25 pa\u015Bum\u0101tara\u1E25 \u096519\u0965</p><p>\u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0438 <em>(m\u0101he\u015Bvar\u012B)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438 <em>(\u0101dy\u0101\u1E25)</em>, [\u0447\u044C\u0435\u0439 \u0441\u0444\u0435\u0440\u043E\u0439 \u0432\u043B\u0438\u044F\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0433\u0440\u0443\u043F\u043F\u0430 <em>(varga)</em> \xABka\xBB <em>(ka)</em> \u0438 \u0442.\u0434. <em>(\u0101di\u1E63u)</em>, \u043C\u0430\u0442\u0435\u0440\u0438 <em>(m\u0101tara\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(pa\u015Bu)</em>, [\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0438\u0445 \u0432\u0435\u0440\u0445\u043E\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438]</p></div><div class="stanza"><a href="#s3.20" id="s3.20" class="num">3.20</a><p class="sans">\u0924\u094D\u0930\u093F\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u0902 \u0924\u0948\u0932\u0935\u0926\u093E\u0938\u0947\u091A\u094D\u092F\u092E\u094D \u0965\u0968\u0966\u0965</p><p class="trans">Tri\u1E63u caturtha\u1E41 tailavad\u0101secyam \u096520\u0965</p><p>\u0427\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C] <em>(caturtham)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043B\u0438\u0432\u0430\u0442\u044C <em>(\u0101secyam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443] \u043C\u0430\u0441\u043B\u0430 <em>(taila)</em> \u0432 [\u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435] \u0442\u0440\u0438 <em>(tri\u1E63u)</em> <em>(\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D)</em></p></div><div class="stanza"><a href="#s3.21" id="s3.21" class="num">3.21</a><p class="sans">\u092E\u0917\u094D\u0928\u0903 \u0938\u094D\u0935\u091A\u093F\u0924\u094D\u0924\u0947\u0928 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D \u0965\u0968\u0967\u0965</p><p class="trans">Magna\u1E25 svacittena pravi\u015Bet \u096521\u0965</p><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C [\u0432 \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(pravi\u015Bet)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C [\u0432 \u043D\u0435\u0433\u043E] <em>(magna\u1E25)</em> \u0441\u0432\u043E\u0438\u043C <em>(sva)</em> \u0443\u043C\u043E\u043C <em>(cittena)</em> [\u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C \u043E\u0442 \u043C\u044B\u0441\u043B\u0435\u0439]</p></div><div class="stanza"><a href="#s3.22" id="s3.22" class="num">3.22</a><p class="sans">\u092A\u094D\u0930\u093E\u0923\u0938\u092E\u093E\u091A\u093E\u0930\u0947 \u0938\u092E\u0926\u0930\u094D\u0936\u0928\u092E\u094D \u0965\u0968\u0968\u0965</p><p class="trans">Pr\u0101\u1E47asam\u0101c\u0101re samadar\u015Banam \u096522\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0435, \u043D\u043E \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435, \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(sam\u0101c\u0101re)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(\u0419\u043E\u0433\u0430)</em> <em>(pr\u0101\u1E47a)</em>, [\u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442] \u0440\u0430\u0432\u043D\u043E\u0435 <em>(sama)</em> \u0432\u0438\u0434\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C \u0419\u043E\u0433 \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0432\u0441\u0435\u0433\u043E]</p></div><div class="stanza"><a href="#s3.23" id="s3.23" class="num">3.23</a><p class="sans">\u092E\u0927\u094D\u092F\u0947\u093D\u0935\u0930\u092A\u094D\u0930\u0938\u0935\u0903 \u0965\u0968\u0969\u0965</p><p class="trans">Madhye&#39;varaprasava\u1E25 \u096523\u0965</p><p>\u041D\u0430 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u043D\u043E\u043C \u044D\u0442\u0430\u043F\u0435 [\u043D\u0435 \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438\u043B\u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(madhye)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0431\u044B\u0442\u044C \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(prasava\u1E25)</em> \u043D\u0438\u0437\u043A\u0438\u0445 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0443\u043C\u0430] <em>(avara)</em></p></div><div class="stanza"><a href="#s3.24" id="s3.24" class="num">3.24</a><p class="sans">\u092E\u093E\u0924\u094D\u0930\u093E\u0938\u094D\u0935\u092A\u094D\u0930\u0924\u094D\u092F\u092F\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0928\u0937\u094D\u091F\u0938\u094D\u092F \u092A\u0941\u0928\u0930\u0941\u0924\u094D\u0925\u093E\u0928\u092E\u094D \u0965\u0968\u096A\u0965</p><p class="trans">M\u0101tr\u0101svapratyayasandh\u0101ne na\u1E63\u1E6Dasya punarutth\u0101nam \u096524\u0965</p><p>\u041F\u0440\u0438 \u0441\u043B\u0438\u044F\u043D\u0438\u0438 <em>(sandh\u0101ne)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u042F <em>(svapratyaya)</em> \u0441 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(m\u0101tr\u0101)</em>, \u0432\u043D\u043E\u0432\u044C [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(punar utth\u0101nam)</em> [\u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435] \u0438\u0441\u0447\u0435\u0437\u043B\u043E <em>(na\u1E63\u1E6Dasya)</em> [\u0438\u0437-\u0437\u0430 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u043D\u0438\u0437\u043A\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0443\u043C\u0430]</p></div><div class="stanza"><a href="#s3.25" id="s3.25" class="num">3.25</a><p class="sans">\u0936\u093F\u0935\u0924\u0941\u0932\u094D\u092F\u094B \u091C\u093E\u092F\u0924\u0947 \u0965\u0968\u096B\u0965</p><p class="trans">\u015Aivatulyo j\u0101yate \u096525\u0965</p><p>[\u0412\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 \u0419\u043E\u0433, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F,] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(j\u0101yate)</em> \u0440\u0430\u0432\u043D\u044B\u043C <em>(tulya\u1E25)</em> \u0428\u0438\u0432\u0435 <em>(\u015Biva)</em></p></div><div class="stanza"><a href="#s3.26" id="s3.26" class="num">3.26</a><p class="sans">\u0936\u0930\u0940\u0930\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u0935\u094D\u0930\u0924\u092E\u094D \u0965\u0968\u096C\u0965</p><p class="trans">\u015Aar\u012Brav\u1E5Bttirvratam \u096526\u0965</p><p>\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 <em>(v\u1E5Btti\u1E25)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(\u015Bar\u012Bra)</em> \u2014 [\u0435\u0433\u043E] \u043E\u0431\u0435\u0442 <em>(vratam)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0436\u0438\u0442\u044C \u0432 \u0442\u0435\u043B\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437-\u0437\u0430 \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u043A \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0443, \u043A\u0430\u043A \u0430\u043A\u0442 \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u044F]</p></div><div class="stanza"><a href="#s3.27" id="s3.27" class="num">3.27</a><p class="sans">\u0915\u0925\u093E \u091C\u092A\u0903 \u0965\u0968\u096D\u0965</p><p class="trans">Kath\u0101 japa\u1E25 \u096527\u0965</p><p>[\u0415\u0433\u043E] \u0440\u0435\u0447\u044C <em>(kath\u0101)</em> \u2014 \u0448\u0435\u043F\u0442\u0430\u043D\u0438\u0435 [\u043C\u0430\u043D\u0442\u0440\u044B \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u044B] <em>(japa\u1E25)</em></p></div><div class="stanza"><a href="#s3.28" id="s3.28" class="num">3.28</a><p class="sans">\u0926\u093E\u0928\u092E\u093E\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0965\u0968\u096E\u0965</p><p class="trans">D\u0101nam\u0101tmaj\xF1\u0101nam \u096528\u0965</p><p>\u0417\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em> \u2014 [\u0435\u0433\u043E] \u0434\u0430\u0440 <em>(d\u0101nam)</em> [\u0432\u0441\u0435\u043C \u043D\u0430\u043C]</p></div><div class="stanza"><a href="#s3.29" id="s3.29" class="num">3.29</a><p class="sans">\u092F\u094B\u093D\u0935\u093F\u092A\u0938\u094D\u0925\u094B \u091C\u094D\u091E\u093E\u0939\u0947\u0924\u0941\u0936\u094D\u091A \u0965\u0968\u096F\u0965</p><p class="trans">Yo&#39;vipastho j\xF1\u0101hetu\u015Bca \u096529\u0965</p><p>\u0422\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0443\u043A\u043E\u0440\u0435\u043D\u0451\u043D [\u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0441\u0438\u043B, \u015Bakticakra] <em>(avipastha\u1E25)</em>, \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 <em>(ca)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0440\u0443\u0434\u0438\u0435\u043C <em>(hetu\u1E25)</em> \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u0438 <em>(j\xF1\u0101)</em></p></div><div class="stanza"><a href="#s3.30" id="s3.30" class="num">3.30</a><p class="sans">\u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u091A\u092F\u094B\u093D\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u092E\u094D \u0965\u0969\u0966\u0965</p><p class="trans">Sva\u015Baktipracayo&#39;sya vi\u015Bvam \u096530\u0965</p><p>\u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C, \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u043D\u0438\u0435\u043C, <em>(pracaya\u1E25)</em> \u0435\u0433\u043E [\u0419\u043E\u0433\u0430] \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva... asya)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em></p></div><div class="stanza"><a href="#s3.31" id="s3.31" class="num">3.31</a><p class="sans">\u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u094C \u0965\u0969\u0967\u0965</p><p class="trans">Sthitilayau \u096531\u0965</p><p>\u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(sthiti)</em> [\u0438 \u0435\u0451] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(layau)</em> [\u0442\u0430\u043A\u0436\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u043D\u0438\u0435\u043C \u0435\u0433\u043E \u0421\u0438\u043B\u044B]</p></div><div class="stanza"><a href="#s3.32" id="s3.32" class="num">3.32</a><p class="sans">\u0924\u0924\u094D\u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u093E\u0935\u092A\u094D\u092F\u0928\u093F\u0930\u093E\u0938\u0903 \u0938\u0902\u0935\u0947\u0924\u094D\u0924\u0943\u092D\u093E\u0935\u093E\u0924\u094D \u0965\u0969\u0968\u0965</p><p class="trans">Tatprav\u1E5Btt\u0101vapyanir\u0101sa\u1E25 sa\u1E41vett\u1E5Bbh\u0101v\u0101t \u096532\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 <em>(prav\u1E5Bttau)</em> \u0442\u0435 [\u0442\u0440\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430: \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(tad)</em>, [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0419\u043E\u0433\u0430] \u043D\u0435 \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(anir\u0101sa\u1E25)</em> \u0432 \u0441\u0432\u044F\u0437\u0438 \u0441 [\u0435\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C <em>(bh\u0101v\u0101t)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E <em>(sa\u1E41vett\u1E5B)</em></p></div><div class="stanza"><a href="#s3.33" id="s3.33" class="num">3.33</a><p class="sans">\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092F\u094B\u0930\u094D\u092C\u0939\u093F\u0930\u094D\u092E\u0928\u0928\u092E\u094D \u0965\u0969\u0969\u0965</p><p class="trans">Sukhadu\u1E25khayorbahirmananam \u096533\u0965</p><p>[\u042D\u0442\u043E\u0442 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 \u0419\u043E\u0433] \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 <em>(mananam)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043E\u043B\u044C <em>(sukhadu\u1E25khayo\u1E25)</em> \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435 <em>(bahis)</em></p></div><div class="stanza"><a href="#s3.34" id="s3.34" class="num">3.34</a><p class="sans">\u0924\u0926\u094D\u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0938\u094D\u0924\u0941 \u0915\u0947\u0935\u0932\u0940 \u0965\u0969\u096A\u0965</p><p class="trans">Tadvimuktastu keval\u012B \u096534\u0965</p><p>[\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0431\u043B\u0430\u0433\u043E\u0440\u043E\u0434\u043D\u044B\u0439 \u0419\u043E\u0433] \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D <em>(vimukta\u1E25)</em> \u043E\u0442 \u0442\u043E\u0433\u043E --\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438-- <em>(tad)</em>, \u0442\u043E <em>(tu)</em> [\u043E\u043D] \u043E\u0434\u0438\u043D <em>(keval\u012B)</em>. [\u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0441\u0432\u043E\u0451\u043C \u0412\u044B\u0441\u0448\u0435\u043C \u042F, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0417\u043D\u0430\u044E\u0449\u0438\u043C \u0438 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F]</p></div><div class="stanza"><a href="#s3.35" id="s3.35" class="num">3.35</a><p class="sans">\u092E\u094B\u0939\u092A\u094D\u0930\u0924\u093F\u0938\u0902\u0939\u0924\u0938\u094D\u0924\u0941 \u0915\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u093E \u0965\u0969\u096B\u0965</p><p class="trans">Mohapratisa\u1E41hatastu karm\u0101tm\u0101 \u096535\u0965</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0442\u043E\u0442, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(pratisa\u1E41hata\u1E25)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moha)</em>, [\u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C] \u0432\u043E\u0432\u043B\u0435\u0447\u0451\u043D <em>(\u0101tm\u0101)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma)</em></p></div><div class="stanza"><a href="#s3.36" id="s3.36" class="num">3.36</a><p class="sans">\u092D\u0947\u0926\u0924\u093F\u0930\u0938\u094D\u0915\u093E\u0930\u0947 \u0938\u0930\u094D\u0917\u093E\u0928\u094D\u0924\u0930\u0915\u0930\u094D\u092E\u0924\u094D\u0935\u092E\u094D \u0965\u0969\u096C\u0965</p><p class="trans">Bhedatirask\u0101re sarg\u0101ntarakarmatvam \u096536\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(bheda)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(tirask\u0101re)</em>, [\u0443 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C <em>(karmatvam)</em> \u0435\u0449\u0451 \u043E\u0434\u043D\u043E <em>(antara)</em> \u0422\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sarga)</em></p></div><div class="stanza"><a href="#s3.37" id="s3.37" class="num">3.37</a><p class="sans">\u0915\u0930\u0923\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u094D\u0935\u0924\u094B\u093D\u0928\u0941\u092D\u0935\u093E\u0924\u094D \u0965\u0969\u096D\u0965</p><p class="trans">Kara\u1E47a\u015Bakti\u1E25 svato&#39;nubhav\u0101t \u096537\u0965</p><p>[\u041B\u044E\u0431\u043E\u0439 \u043C\u043E\u0436\u0435\u0442 \u0443\u0431\u0435\u0434\u0438\u0442\u044C\u0441\u044F \u0432 \u0441\u0432\u043E\u0435\u0439] \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 <em>(kara\u1E47a)</em> \u0441\u0438\u043B\u0435 <em>(\u015Bakti\u1E25)</em> \u043D\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(svata\u1E25)</em> \u043E\u043F\u044B\u0442\u0435 <em>(anubhav\u0101t)</em></p></div><div class="stanza"><a href="#s3.38" id="s3.38" class="num">3.38</a><p class="sans">\u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0926\u094D\u092F\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u094D \u0965\u0969\u096E\u0965</p><p class="trans">Tripad\u0101dyanupr\u0101\u1E47anam \u096538\u0965</p><p>[\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C] \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u0442\u0440\u0451\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F-- <em>(tri-pada)</em> \u0433\u043B\u0430\u0432\u043D\u044B\u043C <em>(\u0101di)</em> [\u0447\u0435\u0442\u0432\u0451\u0440\u0442\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0442\u0440\u0451\u0445, \u043F\u043E\u043B\u043D\u044B\u043C \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430]</p></div><div class="stanza"><a href="#s3.39" id="s3.39" class="num">3.39</a><p class="sans">\u091A\u093F\u0924\u094D\u0924\u0938\u094D\u0925\u093F\u0924\u093F\u0935\u091A\u094D\u091B\u0930\u0940\u0930\u0915\u0930\u0923\u092C\u093E\u0939\u094D\u092F\u0947\u0937\u0941 \u0965\u0969\u096F\u0965</p><p class="trans">Cittasthitivacchar\u012Brakara\u1E47ab\u0101hye\u1E63u \u096539\u0965</p><p>\u041A\u0430\u043A <em>(vat)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 <em>(citta)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(sthiti)</em>, <em>(\u0442\u0430\u043A \u0438)</em> \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bra)</em>, \u043E\u0440\u0433\u0430\u043D\u044B \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em> \u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B --b\u0101hya-- <em>(b\u0101hye\u1E63u)</em> [\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0436\u0438\u0432\u043B\u044F\u0442\u044C, \u0432\u043B\u0438\u0432\u0430\u044F \u0432 \u043D\u0438\u0445 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F]</p></div><div class="stanza"><a href="#s3.40" id="s3.40" class="num">3.40</a><p class="sans">\u0905\u092D\u093F\u0932\u093E\u0937\u093E\u0926\u094D\u092C\u0939\u093F\u0930\u094D\u0917\u0924\u093F\u0903 \u0938\u0902\u0935\u093E\u0939\u094D\u092F\u0938\u094D\u092F \u0965\u096A\u0966\u0965</p><p class="trans">Abhil\u0101\u1E63\u0101dbahirgati\u1E25 sa\u1E41v\u0101hyasya \u096540\u0965</p><p>\u0418\u0437-\u0437\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043F\u043E\u0440\u043E\u0436\u0434\u0451\u043D\u043D\u043E\u0433\u043E \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0435\u043C \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043A\u0430 <em>(abhil\u0101\u1E63\u0101t)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(sa\u1E41v\u0101hyasya)</em> \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0440\u0443\u0436\u0443 <em>(bahirgati\u1E25)</em> [\u0438, \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u0439 \u0446\u0438\u043A\u043B\u0430 \u0441\u0430\u043C\u0441\u0430\u0440\u044B, \u0438\u043B\u0438 \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 \u043E\u0442 \u043E\u0434\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u0436\u0438\u0437\u043D\u0438 \u043A \u0434\u0440\u0443\u0433\u043E\u0439]</p></div><div class="stanza"><a href="#s3.41" id="s3.41" class="num">3.41</a><p class="sans">\u0924\u0926\u093E\u0930\u0942\u0922\u092A\u094D\u0930\u092E\u093F\u0924\u0947\u0938\u094D\u0924\u0924\u094D\u0915\u094D\u0937\u092F\u093E\u091C\u094D\u091C\u0940\u0935\u0938\u0919\u094D\u0915\u094D\u0937\u092F\u0903 \u0965\u096A\u0967\u0965</p><p class="trans">Tad\u0101r\u016B\u1E0Dhapramitestatk\u1E63ay\u0101jj\u012Bvasa\u1E45k\u1E63aya\u1E25 \u096541\u0965</p><p>[\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435,] \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 [\u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0419\u043E\u0433\u0430], \u0447\u044C\u0451 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(pramite\u1E25)</em> \u0443\u043A\u043E\u0440\u0435\u043D\u0438\u043B\u043E\u0441\u044C <em>(\u0101r\u016B\u1E0Dha)</em> \u0432 \u0422\u043E\u043C --\u0432 \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0432 \u0422\u0443\u0440\u044C\u0435-- <em>(tad)</em>, \u043F\u0440\u0438 \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u0438 <em>(k\u1E63ay\u0101t)</em> \u043E\u0442 \u0442\u043E\u0433\u043E [\u0436\u0435\u043B\u0430\u043D\u0438\u044F] <em>(tad)</em> <em>(\u0442\u0430\u043A\u0436\u0435)</em> \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(sa\u1E45k\u1E63aya\u1E25)</em> [\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(j\u012Bva)</em></p></div><div class="stanza"><a href="#s3.42" id="s3.42" class="num">3.42</a><p class="sans">\u092D\u0942\u0924\u0915\u091E\u094D\u091A\u0941\u0915\u0940 \u0924\u0926\u093E \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u094B \u092D\u0942\u092F\u0903 \u092A\u0924\u093F\u0938\u092E\u0903 \u092A\u0930\u0903 \u0965\u096A\u0968\u0965</p><p class="trans">Bh\u016Btaka\xF1cuk\u012B tad\u0101 vimukto bh\u016Bya\u1E25 patisama\u1E25 para\u1E25 \u096542\u0965</p><p>\u0422\u043E\u0433\u0434\u0430, [\u043A\u043E\u0433\u0434\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442] <em>(tad\u0101)</em>, [\u0419\u043E\u0433 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0441\u0432\u043E\u0451 \u0442\u0435\u043B\u043E, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437] \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em>, \u043A\u0430\u043A \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0443 <em>(ka\xF1cuk\u012B)</em> [\u0438, \u0431\u0443\u0434\u0443\u0447\u0438] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u043C <em>(vimukta\u1E25)</em> \u0438 \u0432 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(bh\u016Byas)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C <em>(sama\u1E25)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0443 [\u0428\u0438\u0432\u0435] <em>(pati)</em>, <em>(\u043E\u043D)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0435\u043D \u0438 \u043F\u043E\u043B\u043E\u043D <em>(para\u1E25)</em></p></div><div class="stanza"><a href="#s3.43" id="s3.43" class="num">3.43</a><p class="sans">\u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0903 \u0965\u096A\u0969\u0965</p><p class="trans">Naisargika\u1E25 pr\u0101\u1E47asambandha\u1E25 \u096543\u0965</p><p>\u0421\u0432\u044F\u0437\u044C <em>(sambandha\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0441 \u0442\u0435\u043B\u043E\u043C] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430 <em>(naisargika\u1E25)</em></p></div><div class="stanza"><a href="#s3.44" id="s3.44" class="num">3.44</a><p class="sans">\u0928\u093E\u0938\u093F\u0915\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0927\u094D\u092F\u0938\u0902\u092F\u092E\u093E\u0924\u094D \u0915\u093F\u092E\u0924\u094D\u0930 \u0938\u0935\u094D\u092F\u093E\u092A\u0938\u0935\u094D\u092F\u0938\u094C\u0937\u0941\u092E\u094D\u0928\u0947\u0937\u0941 \u0965\u096A\u096A\u0965</p><p class="trans">N\u0101sik\u0101ntarmadhyasa\u1E41yam\u0101t kimatra savy\u0101pasavyasau\u1E63umne\u1E63u \u096544\u0965</p><p>[\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F --pr\u0101\u1E47a\u015Bakti, \u0438\u043B\u0438 pr\u0101\u1E47a--] [\u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F] \u0432 \u043B\u0435\u0432\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 --i\u1E0D\u0101-- <em>(apasavya)</em>, \u0432 \u043F\u0440\u0430\u0432\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 --pi\u1E45gal\u0101-- <em>(savya)</em> [\u0438] \u0432 su\u1E63umn\u0101 --\u0441\u0440\u0435\u0434\u043D\u0435\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435-- <em>(sau\u1E63umne\u1E63u)</em>.<br> \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E \u0438 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41yam\u0101t)</em> \u0446\u0435\u043D\u0442\u0440\u0430 --\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u042F-- <em>(madhya)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0430\u0441\u043F\u0435\u043A\u0442\u0430 <em>(antar)</em> [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439] pr\u0101\u1E47a\u015Bakti <em>(n\u0101sik\u0101)</em>, [\u0419\u043E\u0433 \u043D\u0430\u0432\u0441\u0435\u0433\u0434\u0430 \u0443\u043A\u043E\u0440\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u0432 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0438 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u042F].</p><p>\u0427\u0442\u043E \u0435\u0449\u0451 [\u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C] <em>(kim)</em> \u043E\u0431 \u044D\u0442\u043E\u043C <em>(atra)</em>?</p></div><div class="stanza"><a href="#s3.45" id="s3.45" class="num">3.45</a><p class="sans">\u092D\u0942\u092F\u0903 \u0938\u094D\u092F\u093E\u0924\u094D\u092A\u094D\u0930\u0924\u093F\u092E\u0940\u0932\u0928\u092E\u094D \u0965\u096A\u096B\u0965</p><p class="trans">Bh\u016Bya\u1E25 sy\u0101tpratim\u012Blanam \u096545\u0965</p><p>[\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0451\u043D\u043D\u043E\u0433\u043E \u0419\u043E\u0433\u0430] \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C <em>(bh\u016Byas)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0431\u044B\u0442\u044C <em>(sy\u0101t)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F, \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435, \u0442\u0430\u043A \u0438 \u0432\u043D\u0435\u0448\u043D\u0435 <em>(pratim\u012Blanam)</em></p></div>',89),n=[t];function i(d,r,c,l,v,h){return m(),s("div",null,n)}var k=a(p,[["render",i]]);export{y as __pageData,k as default};
